<?php

declare(strict_types=1);

function sf_lco_save_series(array $data,int $id=0): int { if(!sf_admin_table_exists('catalog_series'))return 0;$title=trim((string)($data['title']??''));if($title==='')return 0;$slug=trim((string)($data['slug']??''))?:sf_admin_slugify($title);$tz=(string)($data['release_timezone']??sf_lco_timezone());try{new DateTimeZone($tz);}catch(Throwable $e){$tz=sf_lco_timezone();}$payload=['title'=>$title,'slug'=>$slug,'description'=>trim((string)($data['description']??''))?:null,'primary_image_asset_id'=>sf_admin_int($data['primary_image_asset_id']??null),'release_at'=>sf_lco_normalize_schedule($data['release_at']??null,$tz),'release_timezone'=>$tz,'status'=>in_array($data['status']??'draft',['draft','scheduled','published','archived'],true)?$data['status']:'draft'];sf_admin_build_insert_update('catalog_series',$payload,$id);return$id?:((int)(sf_admin_db()?->lastInsertId()?:0)); }
function sf_lco_save_seo(string $type,int $id,array $data): bool { if(!sf_lco_type($type)||$id<=0||!sf_admin_table_exists('catalog_seo_metadata'))return false;$title=trim((string)($data['seo_title']??''));$desc=trim((string)($data['meta_description']??''));$canonical=trim((string)($data['canonical_path']??''));if(sf_lco_len($title)<10||sf_lco_len($title)>190||sf_lco_len($desc)<50||sf_lco_len($desc)>320||!str_starts_with($canonical,'/')||str_contains($canonical,'..'))return false;$sql='INSERT INTO catalog_seo_metadata (entity_type,entity_id,seo_title,meta_description,canonical_path,social_image_asset_id,robots_noindex,updated_by_user_id) VALUES (?,?,?,?,?,?,?,?) ON DUPLICATE KEY UPDATE seo_title=VALUES(seo_title),meta_description=VALUES(meta_description),canonical_path=VALUES(canonical_path),social_image_asset_id=VALUES(social_image_asset_id),robots_noindex=VALUES(robots_noindex),updated_by_user_id=VALUES(updated_by_user_id),updated_at=NOW()';return sf_admin_execute($sql,[$type,$id,$title,$desc,$canonical,sf_admin_int($data['social_image_asset_id']??null),!empty($data['robots_noindex'])?1:0,sf_current_user_id()?:null]); }
function sf_lco_sample_reasons(string $type,array $row): array { $title=sf_lco_title($type,$row);$slug=sf_lco_slug($type,$row);$description=sf_lco_description($type,$row);$text=strtolower($title.' '.$slug.' '.$description);$out=[];if(preg_match('/\b(lorem ipsum|placeholder|sample content|demo content|test product|example item)\b/i',$text))$out[]=['code'=>'explicit_sample_text','confidence'=>98,'evidence'=>$title];if(preg_match('/(^|[-_])(demo|sample|placeholder|test)([-_]|$)/i',$slug))$out[]=['code'=>'sample_slug','confidence'=>95,'evidence'=>$slug];foreach(['image_path','file_path','poster','cover_path'] as$f)if(!empty($row[$f])&&preg_match('/placeholder|sample|demo/i',(string)$row[$f]))$out[]=['code'=>'sample_asset_path','confidence'=>90,'evidence'=>$row[$f]];return$out; }
function sf_lco_scan_samples(bool $persist=true): array { $flags=[];foreach(sf_lco_types() as$type=>$c)foreach(sf_lco_rows($type) as$row)foreach(sf_lco_sample_reasons($type,$row) as$reason){$flag=['entity_type'=>$type,'entity_id'=>(int)$row['id'],'label'=>sf_lco_title($type,$row)]+$reason;$flags[]=$flag;if($persist&&sf_admin_table_exists('catalog_sample_flags'))sf_admin_execute('INSERT INTO catalog_sample_flags (entity_type,entity_id,reason_code,confidence_percent,flag_status,evidence_json) VALUES (?,?,?,?,"open",?) ON DUPLICATE KEY UPDATE confidence_percent=VALUES(confidence_percent),evidence_json=VALUES(evidence_json),flag_status=IF(flag_status="ignored","ignored","open"),updated_at=NOW()',[$type,$row['id'],$reason['code'],$reason['confidence'],sf_lco_json(['label'=>$flag['label'],'evidence'=>$reason['evidence']])]);}return$flags; }
function sf_lco_batch_start(string $actionType,string $confirmation): int { $key=sf_lco_key('batch');$digest=hash('sha256',$confirmation.'|'.$actionType.'|'.$key);sf_admin_execute('INSERT INTO catalog_publication_batches (batch_key,action_type,batch_status,confirmation_digest,created_by_user_id) VALUES (?,?,"processing",?,?)',[$key,$actionType,$digest,sf_current_user_id()?:null]);return(int)(sf_admin_db()?->lastInsertId()?:0); }
function sf_lco_batch_action(int $batch,string $type,int $id,string $action,?array $before,?array $after,string $status='success',string $error=''): void { sf_admin_execute('INSERT INTO catalog_publication_actions (batch_id,entity_type,entity_id,action_type,action_status,before_json,after_json,error_message) VALUES (?,?,?,?,?,?,?,?)',[$batch,$type,$id,$action,$status,$before?sf_lco_json($before):null,$after?sf_lco_json($after):null,$error?:null]); }
function sf_lco_batch_finish(int $batch,array $summary,string $status='completed'): void { sf_admin_execute('UPDATE catalog_publication_batches SET batch_status=?,item_count=?,success_count=?,failure_count=?,summary_json=?,completed_at=NOW() WHERE id=?',[$status,(int)($summary['items']??0),(int)($summary['success']??0),(int)($summary['failed']??0),sf_lco_json($summary),$batch]); }
function sf_lco_update_row(string $type,int $id,array $payload): bool { $c=sf_lco_type($type);if(!$c||$id<=0)return false;$table=$c['table'];$cols=sf_admin_table_columns($table);$payload=array_intersect_key($payload,array_flip($cols));unset($payload['id'],$payload['created_at']);if(!$payload)return false;$sets=[];$params=[];foreach($payload as$k=>$v){$sets[]='`'.sf_lco_identifier($k).'`=?';$params[]=$v;}$params[]=$id;return sf_admin_execute('UPDATE `'.sf_lco_identifier($table).'` SET '.implode(',',$sets).' WHERE id=?',$params); }
function sf_lco_publish_ready(string $confirmation=''): array { if(!hash_equals('PUBLISH',strtoupper(trim($confirmation))))return['ok'=>false,'message'=>'Type PUBLISH exactly.'];$scan=sf_lco_scan();$batch=sf_lco_batch_start('publish_ready',$confirmation);$summary=['items'=>0,'success'=>0,'failed'=>0];foreach($scan['items'] as$item){if($item['status']!=='ready')continue;$type=$item['entity_type'];$c=sf_lco_type($type);$row=$item['row'];$statusCol=$c['status']??'status';if(!array_key_exists($statusCol,$row))continue;$target=$c['publish'];if((string)$row[$statusCol]===$target)continue;$summary['items']++;$before=$row;$ok=sf_lco_update_row($type,(int)$row['id'],[$statusCol=>$target]);$after=$ok?array_merge($before,[$statusCol=>$target]):null;sf_lco_batch_action($batch,$type,(int)$row['id'],'publish_ready',$before,$after,$ok?'success':'failed',$ok?'':'Update failed.');$ok?$summary['success']++:$summary['failed']++;}sf_lco_batch_finish($batch,$summary,$summary['failed']?'completed_with_errors':'completed');return['ok'=>$summary['failed']===0,'batch_id'=>$batch]+$summary; }
function sf_lco_archive_samples(string $confirmation=''): array { if(!hash_equals('ARCHIVE',strtoupper(trim($confirmation))))return['ok'=>false,'message'=>'Type ARCHIVE exactly.'];$flags=sf_admin_table_exists('catalog_sample_flags')?sf_admin_fetch_all('SELECT * FROM catalog_sample_flags WHERE flag_status="open" AND confidence_percent>=90 ORDER BY id ASC'):[];$batch=sf_lco_batch_start('archive_samples',$confirmation);$summary=['items'=>0,'success'=>0,'failed'=>0];foreach($flags as$flag){$type=(string)$flag['entity_type'];$c=sf_lco_type($type);if(!$c)continue;$row=sf_admin_fetch_one('SELECT * FROM `'.sf_lco_identifier($c['table']).'` WHERE id=?',[(int)$flag['entity_id']]);if(!$row)continue;$summary['items']++;$ok=sf_lco_update_row($type,(int)$row['id'],[$c['status']=>$c['archive']]);$after=$ok?array_merge($row,[$c['status']=>$c['archive']]):null;sf_lco_batch_action($batch,$type,(int)$row['id'],'archive_sample',$row,$after,$ok?'success':'failed',$ok?'':'Archive failed.');if($ok){sf_admin_execute('UPDATE catalog_sample_flags SET flag_status="resolved",resolved_by_user_id=?,resolved_at=NOW() WHERE id=?',[sf_current_user_id()?:null,$flag['id']]);$summary['success']++;}else$summary['failed']++;}sf_lco_batch_finish($batch,$summary,$summary['failed']?'completed_with_errors':'completed');return['ok'=>$summary['failed']===0,'batch_id'=>$batch]+$summary; }
function sf_lco_rollback_batch(int $batchId,string $confirmation=''): array { if(!hash_equals('ROLLBACK',strtoupper(trim($confirmation))))return['ok'=>false,'message'=>'Type ROLLBACK exactly.'];$batch=sf_admin_fetch_one('SELECT * FROM catalog_publication_batches WHERE id=? LIMIT 1',[$batchId]);if(!$batch||in_array((string)$batch['batch_status'],['rolled_back','rolling_back'],true))return['ok'=>false,'message'=>'Batch cannot be rolled back.'];$actions=sf_admin_fetch_all('SELECT * FROM catalog_publication_actions WHERE batch_id=? AND action_status="success" ORDER BY id DESC',[$batchId]);sf_admin_execute('UPDATE catalog_publication_batches SET batch_status="rolling_back" WHERE id=?',[$batchId]);$summary=['items'=>count($actions),'success'=>0,'failed'=>0];foreach($actions as$a){$type=(string)$a['entity_type'];$before=$a['before_json']?json_decode((string)$a['before_json'],true):null;$after=$a['after_json']?json_decode((string)$a['after_json'],true):null;$ok=false;if(is_array($before))$ok=sf_lco_update_row($type,(int)$a['entity_id'],$before);elseif(is_array($after)){ $c=sf_lco_type($type);if($c)$ok=sf_admin_execute('DELETE FROM `'.sf_lco_identifier($c['table']).'` WHERE id=?',[(int)$a['entity_id']]); }$ok?$summary['success']++:$summary['failed']++;}sf_admin_execute('UPDATE catalog_publication_batches SET batch_status=?,rolled_back_at=NOW(),summary_json=? WHERE id=?',[$summary['failed']?'rollback_failed':'rolled_back',sf_lco_json($summary),$batchId]);return['ok'=>$summary['failed']===0]+$summary; }
